// MVU Form Handler
document.addEventListener('click', function(e) {
    if (e.target && e.target.classList.contains('mvu-submit-btn')) {
        e.preventDefault();

        // Find the chat message container to scope our inputs
        const messageBlock = e.target.closest('.mes');
        if (!messageBlock) return;

        let text = "[KHỞI TẠO NHÂN VẬT]\n\n";

        const inputs = messageBlock.querySelectorAll('.mvu-input');
        if (inputs.length === 0) return;

        inputs.forEach(input => {
            const label = input.getAttribute('data-label') || "Mục";
            let val = input.value.trim();
            if (!val) val = "(Trống)";
            text += `- ${label}: ${val}\n`;
        });

        // Output to console for debugging
        console.log("MVU Form Data:", text);

        // Find send textarea
        const ta = document.getElementById('send_textarea');
        const btn = document.getElementById('send_but');
        if (ta && btn) {
            // Because React/ST tracks input events:
            const nativeInputValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, "value").set;
            nativeInputValueSetter.call(ta, text);
            ta.dispatchEvent(new Event('input', { bubbles: true }));

            // Click send
            btn.click();

            // Change button state
            e.target.disabled = true;
            e.target.textContent = "✅ ĐÃ GỬI!";
            e.target.style.background = "#2a4a2a";
            e.target.style.color = "#e8d5a3";
        } else {
            alert("Không tìm thấy nút gửi hoặc ô chat.");
        }
    }
});

