(function() {
  var STORAGE_KEY = 'mvu_char_form_data';
  var _bound = new WeakSet();
  var _observer = null;

  /* ── Save all form inputs to sessionStorage ── */
  function saveFormState(container) {
    if (!container) return;
    var inputs = container.querySelectorAll('.mvu-input');
    if (inputs.length === 0) return;
    var data = {};
    inputs.forEach(function(el) {
      var label = el.getAttribute('data-label');
      if (label) {
        data[label] = el.value || '';
      }
    });
    try { sessionStorage.setItem(STORAGE_KEY, JSON.stringify(data)); } catch(e) {}
  }

  /* ── Restore form inputs from sessionStorage ── */
  function restoreFormState(container) {
    if (!container) return;
    var raw;
    try { raw = sessionStorage.getItem(STORAGE_KEY); } catch(e) { return; }
    if (!raw) return;
    var data;
    try { data = JSON.parse(raw); } catch(e) { return; }
    var inputs = container.querySelectorAll('.mvu-input');
    inputs.forEach(function(el) {
      var label = el.getAttribute('data-label');
      if (label && data[label]) {
        el.value = data[label];
      }
    });
  }

  /* ── Debounced auto-save on input ── */
  var _saveTimer = null;
  function onInputChange(e) {
    var container = e.target.closest('.mes_text') || e.target.closest('[class*="mes"]') || document.body;
    if (_saveTimer) clearTimeout(_saveTimer);
    _saveTimer = setTimeout(function() { saveFormState(container); }, 300);
  }

  /* ── Prevent SillyTavern auto-scroll while user is in the form ── */
  var _userInForm = false;
  function onFormFocus() { _userInForm = true; }
  function onFormBlur()  { setTimeout(function(){ _userInForm = false; }, 500); }

  /* ── Override ST scroll behavior when user is in form ── */
  var _origScrollIntoView = Element.prototype.scrollIntoView;
  Element.prototype.scrollIntoView = function(opts) {
    if (_userInForm) return; // Block auto-scroll while editing form
    return _origScrollIntoView.call(this, opts);
  };

  /* ── Bind events to a form container ── */
  function bindForm(container) {
    var inputs = container.querySelectorAll('.mvu-input');
    inputs.forEach(function(el) {
      if (_bound.has(el)) return;
      _bound.add(el);
      el.addEventListener('input', onInputChange);
      el.addEventListener('change', onInputChange);
      el.addEventListener('focus', onFormFocus);
      el.addEventListener('blur', onFormBlur);

      /* Prevent Enter key from triggering ST send */
      el.addEventListener('keydown', function(ev) {
        if (ev.key === 'Enter' && el.tagName !== 'TEXTAREA') {
          ev.preventDefault();
          ev.stopPropagation();
        }
      });
    });

    /* Bind submit button */
    var btns = container.querySelectorAll('.mvu-submit-btn');
    btns.forEach(function(btn) {
      if (_bound.has(btn)) return;
      _bound.add(btn);
      btn.addEventListener('click', handleSubmit);
    });

    /* Restore previously saved data */
    restoreFormState(container);
  }

  /* ── Submit handler ── */
  function handleSubmit(e) {
    e.preventDefault();
    e.stopPropagation();

    var btn = e.target.closest('.mvu-submit-btn') || e.target;
    var msgBlock = btn.closest('.mes_text') || btn.closest('.mes_block') || btn.closest('[class*="mes"]') || document.body;
    var inputs = msgBlock.querySelectorAll('.mvu-input');
    var lines = ['=== KHỞI TẠO NHÂN VẬT ===', ''];
    var filled = 0;

    inputs.forEach(function(el) {
      var label = el.getAttribute('data-label') || 'Unknown';
      var value = (el.value || '').trim();
      if (value) {
        lines.push(label + ': ' + value);
        filled++;
      }
    });

    if (filled === 0) {
      alert('Vui lòng điền ít nhất một thông tin trước khi khởi tạo!');
      return;
    }

    lines.push('');
    lines.push('=== KẾT THÚC THÔNG TIN NHÂN VẬT ===');
    var text = lines.join('\n');

    var textarea = document.getElementById('send_textarea');
    if (!textarea) {
      alert('Không tìm thấy khung chat!\n\n' + text);
      return;
    }

    /* React-compatible value setter */
    var setter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
    setter.call(textarea, text);
    textarea.dispatchEvent(new Event('input', { bubbles: true }));

    setTimeout(function() {
      var sendBtn = document.getElementById('send_but');
      if (sendBtn) sendBtn.click();
    }, 150);

    /* Visual feedback */
    btn.textContent = '✅ Đã gửi! (' + filled + '/' + inputs.length + ' mục)';
    btn.style.background = 'linear-gradient(180deg, #4a8a4a 0%, #367836 100%)';
    btn.disabled = true;

    /* Clear saved state after successful send */
    try { sessionStorage.removeItem(STORAGE_KEY); } catch(e) {}

    setTimeout(function() {
      btn.textContent = '⚔️ KHỞI TẠO THẾ GIỚI ⚔️';
      btn.style.background = 'linear-gradient(180deg, #d4a844 0%, #b38b36 100%)';
      btn.disabled = false;
    }, 3000);
  }

  /* ── Main setup: observe DOM for form appearance ── */
  function setup() {
    /* Scan existing messages */
    document.querySelectorAll('.mes_text').forEach(function(msg) {
      if (msg.querySelector('.mvu-input')) bindForm(msg);
    });

    /* Watch for new messages */
    _observer = new MutationObserver(function(mutations) {
      mutations.forEach(function(m) {
        m.addedNodes.forEach(function(node) {
          if (node.nodeType !== 1) return;
          /* Check if the added node IS or CONTAINS the form */
          var targets = [];
          if (node.classList && node.classList.contains('mes_text')) {
            targets.push(node);
          }
          if (node.querySelectorAll) {
            node.querySelectorAll('.mes_text').forEach(function(mt) { targets.push(mt); });
          }
          /* Also check if mvu-input was added directly */
          if (node.querySelector && node.querySelector('.mvu-input')) {
            var parent = node.closest('.mes_text') || node;
            targets.push(parent);
          }
          targets.forEach(function(t) {
            if (t.querySelector('.mvu-input')) bindForm(t);
          });
        });
      });
    });

    _observer.observe(document.body, { childList: true, subtree: true });
  }

  /* Initialize */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', setup);
  } else {
    setup();
  }
})();

